const chatId = $('Start').first().json.tool_input.chat_id;

return [
  {
    json: {
      confirmation_message: 'Your cart is empty. Please add some items first!',
      chat_id: chatId,
      error: true,
    },
  },
];

const startInput = $('Start').first().json.tool_input || {};
const chatId = startInput.chat_id;
const address = startInput.address;

const normalizeUnit = (value) => {
  const map = {
    kg: 'kg', kilo: 'kg', kilos: 'kg', kilogram: 'kg', kilograms: 'kg',
    g: 'g', gm: 'g', gram: 'g', grams: 'g',
    l: 'l', lt: 'l', ltr: 'l', litre: 'l', litres: 'l', liter: 'l', liters: 'l',
    ml: 'ml', millilitre: 'ml', millilitres: 'ml', milliliter: 'ml', milliliters: 'ml',
  };
  return map[String(value || '').toLowerCase().trim()] || String(value || '').toLowerCase().trim() || 'pcs';
};
const formatQty = (value) => Number.isInteger(Number(value)) ? String(Number(value)) : String(Number(Number(value).toFixed(3)));
const quantityLabel = (itemName, unit, quantity) => {
  const lower = String(itemName || '').toLowerCase();
  const packMatch = lower.match(/(\d+(?:\.\d+)?)\s*(kg|kilo|kilos|kilogram|kilograms|g|gm|gram|grams|ml|l|lt|ltr|litre|litres|liter|liters|millilitre|millilitres|milliliter|milliliters)\b/i);
  if (/\bloose\b/.test(lower) && packMatch) {
    return normalizeUnit(packMatch[2]);
  }
  if (packMatch) {
    return Number(quantity) === 1 ? 'pack' : 'packs';
  }
  const normalizedUnit = normalizeUnit(unit);
  return normalizedUnit || 'pcs';
};

const rawCartRows = $('Get Active Cart for Checkout').all();
const allItems = [];
for (const entry of rawCartRows) {
  const row = entry && entry.json ? entry.json : null;
  if (row && row.cart_id) {
    allItems.push(row);
  }
}

if (allItems.length === 0) {
  return [{
    json: {
      confirmation_message: 'Your cart is empty. Please add some items first!',
      chat_id: chatId,
      error: true,
    },
  }];
}

const firstItem = allItems[0];
const cartId = firstItem.cart_id;

let subtotal = 0;
const orderItems = [];
for (const row of allItems) {
  const quantity = Number(row.quantity);
  const unitPrice = parseFloat(row.unit_price);
  const lineTotal = quantity * unitPrice;
  subtotal += lineTotal;

  orderItems.push({
    sku: row.sku,
    original_name: row.original_name,
    quantity,
    unit: row.unit || '',
    unit_price: unitPrice,
    line_total: lineTotal,
    display_quantity_unit: quantityLabel(row.original_name, row.unit, quantity),
  });
}

const promoRowsRaw = $input.all();
const promoRows = [];
for (const entry of promoRowsRaw) {
  const row = entry && entry.json ? entry.json : null;
  if (row && row.promo_code) {
    promoRows.push(row);
  }
}

let totalDiscount = 0;
const appliedPromos = [];

if (promoRows.length > 0) {
  const promo = promoRows[0];
  const minCart = parseFloat(promo.min_cart_value || 0);

  if (minCart === 0 || subtotal >= minCart) {
    let discount = 0;
    if (promo.discount_type === 'percentage') {
      discount = parseFloat((subtotal * parseFloat(promo.discount_value) / 100).toFixed(2));
    } else if (promo.discount_type === 'flat') {
      discount = parseFloat(Math.min(parseFloat(promo.discount_value), subtotal).toFixed(2));
    }

    if (discount > 0) {
      totalDiscount = discount;
      let description = promo.description;
      if (!description) {
        if (promo.discount_type === 'percentage') {
          description = String(promo.discount_value) + '% off your order';
        } else {
          description = 'Rs.' + String(discount) + ' off your order';
        }
      }

      appliedPromos.push({
        code: promo.promo_code,
        discount,
        description,
      });
    }
  }
}

const finalTotal = parseFloat((subtotal - totalDiscount).toFixed(2));

const itemLines = orderItems
  .map((entry) => `- ${entry.original_name} x ${formatQty(entry.quantity)} ${entry.display_quantity_unit} = Rs.${entry.line_total.toFixed(2)}`)
  .join('\n');

let discountLines = '';
if (appliedPromos.length > 0) {
  const promoLines = appliedPromos.map((promo) => `  ${promo.code}: -Rs.${promo.discount.toFixed(2)} (${promo.description})`);
  discountLines = '\nDiscounts:\n' + promoLines.join('\n');
}

// Promo nudge — show next-tier promo if nothing applied
let promoNudge = '';
if (appliedPromos.length === 0 && promoRows.length > 0) {
  const p = promoRows[0];
  const minNeeded = parseFloat(p.min_cart_value || 0);
  if (minNeeded > 0 && subtotal < minNeeded) {
    const gap = (minNeeded - subtotal).toFixed(2);
    const reward = p.discount_type === 'percentage'
      ? p.discount_value + '% off'
      : 'Rs.' + p.discount_value + ' off';
    promoNudge = '\n💡 Add Rs.' + gap + ' more to get ' + reward + ' (code: ' + p.promo_code + ')';
  }
}

const billMsg =
  'Order Summary\n\n' +
  itemLines +
  discountLines +
  promoNudge +
  '\n\n' +
  'Deliver to: ' + String(address) + '\n' +
  'Subtotal: Rs.' + subtotal.toFixed(2) + '\n' +
  (totalDiscount > 0 ? 'You save: Rs.' + totalDiscount.toFixed(2) + '\n' : '') +
  'Total Payable: Rs.' + String(finalTotal);

return [{
  json: {
    order_id: 'ORD-' + String(chatId) + '-' + String(Date.now()),
    cart_id: cartId,
    chat_id: chatId,
    store_id: firstItem.store_id || 1,
    address,
    subtotal_before_discounts: subtotal,
    total_discount_applied: totalDiscount,
    final_order_total: finalTotal,
    applied_promos: appliedPromos,
    items_in_final_order: orderItems,
    confirmation_message: billMsg,
    error: false,
  },
}];

const d = item.json || {};

if (d.error) {
  return {
    json: d,
  };
}

const orderJson = JSON.stringify({
  order_id: d.order_id,
  cart_id: d.cart_id,
  chat_id: d.chat_id,
  store_id: d.store_id,
  address: d.address,
  subtotal_before_discounts: d.subtotal_before_discounts,
  total_discount_applied: d.total_discount_applied,
  final_order_total: d.final_order_total,
  applied_promos: d.applied_promos,
  items_in_final_order: d.items_in_final_order,
}).replace(/'/g, "''");

return {
  json: {
    ...d,
    order_details_json_safe: orderJson,
  },
};

const d = $('Prep Pending Order').first().json || {};

return {
  json: {
    confirmation_message: d.confirmation_message,
    chat_id: d.chat_id,
    error: d.error || false,
  },
};

